def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    base_exp = np.exp(-item / (bins + 1e-5))
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    priority += ((ratio - a) ** 6)/(a * b + 1) * np.sin(ratio * b / (a + 0.5))
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 2
            if bin_cap % 2 < 1:
                priority += np.log1p(bin_cap * item) * 3
            else:
                priority -= np.sqrt(bin_cap / (item + 0.1)) * 4
        elif 5 < ratio <= 8:
            for c in range(1, int(np.ceil(ratio)) + 4):
                for d in range(1, c + 3):
                    term = ((ratio - c) ** 4) * np.cos(ratio * c) / (d + 1)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
            if i % 2 == 0:
                priority += np.sin(ratio * i) * 1.3
            else:
                priority -= np.cos(ratio * i) * 1.3
        elif 2 < ratio <= 5:
            s = 0
            for e in range(1, 15):
                s += ((ratio - 2) ** e) / (e * 2.0) * np.sin(e * ratio)
            priority = (s * np.cos(6 * ratio)) - np.log(ratio) * 8 + np.tanh(3 * (5 - ratio)) * 2
            if bin_cap < item * 2:
                priority += np.sqrt(item * bin_cap) * 3
            else:
                priority -= np.exp(-ratio) * 3.5
        elif 1 <= ratio <= 2:
            s = 0
            for f in range(1, 12):
                s += ((2 - ratio) ** f) / (f ** 2 + 1) * np.cos(f * ratio * 1.2)
            priority = s + np.exp(-1 / (ratio + 0.1)) * 3.2
            for g in range(1, 6):
                priority += np.sin(g * ratio * i) * ((ratio - 1) ** g) / (g + 0.5)
        elif 0.5 < ratio < 1:
            s = 0
            for h in range(1, 15):
                s += ((1 - ratio) ** h) / (h * 3) * np.sin(h * ratio * 1.5)
            priority = s
            if (i + int(item * 2)) % 5 == 1:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 7):
                priority += ((1 - ratio) ** j) * np.cos(j * item * 1.3) * 0.8
        elif 0.2 <= ratio <= 0.5:
            s = 0
            for k in range(1, 12):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 2.5)
            priority = s + 2 / (bin_cap + 5)
            if int(item * 1.7) % 3 == 2:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for l in range(1, 8):
                priority += ((0.5 - ratio) ** l) / (l * 7) * np.sin(item * l * 1.2)
        else:
            s = 0
            for m in range(1, 12):
                s += ((0.2 - ratio) ** m) / (m * 6) * np.sin(m * item * 0.95)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.85) % 4 == 0:
                priority *= 2.7
            else:
                priority /= 2.7
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.2) * 5
            for n in range(1, 9):
                priority += ((0.2 - ratio) ** n) / (n * 8) * np.cos(item * n * 0.85)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
        for o in range(1, 5):
            if (i + o) % 4 == 0:
                priority += np.sin(ratio * (i + o)) * 0.4
            else:
                priority -= np.cos(ratio * (i + o)) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.2) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.2) * 0.7
        if bin_cap % 2 == 0:
            priority += np.sqrt(bin_cap) * np.tanh(ratio * 2)
        else:
            priority -= np.log1p(bin_cap) * np.sin(ratio * 3)
        priorities[i] = priority * base_exp[i]
    return priorities
